"use client";

import * as React from "react";

import { TeamQuestNameEditor } from "./parts/team-quest-name-editor";
import { TeamQuestChapters } from "./parts/team-quest-chapters";
import { TeamQuestLogRoot } from "./parts/team-quest-log-root";
import type { TeamQuestLogHandle, TeamQuestLogProps } from "./types";

/**
 * Tier A — the batteries-included assembly: `Root` + `TeamQuestNameEditor`
 * (gated by `showNameEditor`) + `TeamQuestChapters` (gated by `showChapters`).
 * Contains **no logic the parts don't** — a hand-assembled layout (`Root` + a
 * subset of parts) gets identical title resolution, beat derivation, and
 * fire-once telemetry. Forwards the imperative handle from `Root`.
 *
 * A light team narrative overlay: a skippable quest name (never forced) + a
 * milestone-chapter timeline (done / current / upcoming), team-scoped.
 */
export const TeamQuestLog01 = React.forwardRef<
  TeamQuestLogHandle,
  TeamQuestLogProps
>(function TeamQuestLog01(
  { showNameEditor = true, showChapters = true, ...rest },
  ref,
) {
  return (
    <TeamQuestLogRoot ref={ref} {...rest}>
      {showNameEditor ? <TeamQuestNameEditor /> : null}
      {showChapters ? <TeamQuestChapters /> : null}
    </TeamQuestLogRoot>
  );
});

// Tier A — batteries-included assembly.
export { TeamQuestLog01 } from "./team-quest-log-01";

// Tier B — headless provider + flat à-la-carte context parts.
export { TeamQuestLogRoot } from "./parts/team-quest-log-root";
export { TeamQuestNameEditor } from "./parts/team-quest-name-editor";
export { TeamQuestChapters } from "./parts/team-quest-chapters";

// Tier C — standalone, context-free primitives.
export { QuestTitle, QuestNameField } from "./parts/team-quest-name-editor";
export { ChapterRail, EmptyNarrative } from "./parts/team-quest-chapters";
export { ChapterBeat } from "./parts/chapter-beat";

// Context consumer for hand-assembled layouts.
export { useTeamQuestLog } from "./hooks/use-team-quest-log";

// Pure helpers (a hand-assembly resolves identically).
export { resolveQuestTitle } from "./lib/resolve-title";
export { deriveBeats } from "./lib/derive-beats";

// Public types.
export type {
  Team,
  Milestone,
  NarrativeChapter,
  GamificationEvent,
  BeatState,
  DerivedBeat,
  TeamQuestLogProps,
  TeamQuestLogBaseProps,
  TeamQuestLogRootProps,
  TeamQuestLogHandle,
  TeamQuestLogContextValue,
  QuestTitleProps,
  QuestNameFieldProps,
  ChapterBeatProps,
  ChapterRailProps,
} from "./types";

import type { ReactNode } from "react";

/**
 * `team-quest-log-01` — public type surface.
 *
 * Framework-free (no `"use client"`). Per system D-03 the domain slice is
 * **re-declared locally** — this component imports nothing from another registry
 * component. The `gamification-system` §4 model is the source of truth these are
 * copied from (only the rendered fields), byte-faithful, not imported.
 */

/** This team (D-15 subset). `name` is the fallback title; `questName` the chosen one. */
export interface Team {
  id: string;
  name: string;
  /** The chosen quest title; empty/blank → falls back to `name` (never forced). */
  questName?: string;
}

/** A host-owned milestone — the shared spine each chapter frames (D-09). */
export interface Milestone {
  id: string;
  label: string;
  done: boolean;
  /** ISO 8601 — optional "completed on" affordance. */
  doneAt?: string;
  order: number;
}

/** A narrative beat framing a milestone. */
export interface NarrativeChapter {
  id: string;
  title: string;
  /** Links the beat to its `Milestone` (the shared spine, D-09). */
  milestoneId: string;
  order: number;
}

/** The local slice of the system §6 union — the one event this component emits. */
export type GamificationEvent = {
  type: "narrative.chapter-viewed";
  teamId: string;
  chapterId: string;
};

/** Resolved beat state (see `lib/derive-beats.ts`). */
export type BeatState = "done" | "current" | "upcoming";

/** One derived beat — the render-ready unit. */
export interface DerivedBeat {
  chapter: NarrativeChapter;
  /** Resolved by `milestoneId`; `undefined` → unresolved (renders gracefully + warns). */
  milestone?: Milestone;
  state: BeatState;
  /** `true` → `milestoneId` matched no milestone. */
  unresolved: boolean;
}

/** Data + behavioral surface shared by the assembly and the headless Root. */
export interface TeamQuestLogBaseProps {
  /** The team — literal name (fallback) + optional quest name (D-15 subset). */
  team: Team;
  /** Host-owned milestones — the shared spine (D-09). */
  milestones: Milestone[];
  /** The narrative beats; each frames a milestone. Empty → quiet empty state. */
  chapters: NarrativeChapter[];
  /** Allow inline name editing. Default `true`; `false` → display-only title. */
  editableName?: boolean;
  /** Fires on save. Empty/blank ⇒ revert to the team's literal name (never forced). */
  onQuestNameChange?: (questName: string) => void;
  /** Telemetry (system §6, D-07) — emits `narrative.chapter-viewed`, fire-once per mount. */
  onEvent?: (event: GamificationEvent) => void;
  /** Fires when a chapter beat is activated; also drives the telemetry fallback when IO is unavailable. */
  onChapterClick?: (chapter: NarrativeChapter) => void;
  /** Override an individual beat's render. */
  renderChapter?: (ctx: {
    chapter: NarrativeChapter;
    state: BeatState;
  }) => ReactNode;
  className?: string;
  "aria-label"?: string;
}

/** Props for the batteries-included `TeamQuestLog01` assembly. */
export interface TeamQuestLogProps extends TeamQuestLogBaseProps {
  /** Show the quest-name editor. Default `true`. */
  showNameEditor?: boolean;
  /** Show the chapter timeline. Default `true`. */
  showChapters?: boolean;
}

/** Props for the headless provider `TeamQuestLogRoot`. */
export interface TeamQuestLogRootProps extends TeamQuestLogBaseProps {
  children: ReactNode;
}

/** Light imperative handle (exposed via `forwardRef` on Root + the assembly). */
export interface TeamQuestLogHandle {
  /** Enter edit mode + focus the quest-name input. */
  focusNameEditor(): void;
  /** Scroll the matching chapter beat into view. */
  scrollToChapter(chapterId: string): void;
}

/** The value every context part reads — one source of truth. */
export interface TeamQuestLogContextValue {
  team: Team;
  /** Resolved title = `questName?.trim() || name`. */
  title: string;
  /** `true` when falling back to the literal team name. */
  isDefaultTitle: boolean;
  beats: DerivedBeat[];
  editableName: boolean;
  /** `true` when the edit affordance should show (editable + a save handler wired). */
  canEditName: boolean;
  // Name draft/edit state (transient UI state — not data state, D-06).
  editing: boolean;
  draft: string;
  startEditing(): void;
  setDraft(value: string): void;
  saveDraft(): void;
  cancelEditing(): void;
  // Chapter interaction + telemetry.
  onChapterClick?: (chapter: NarrativeChapter) => void;
  onEvent?: (event: GamificationEvent) => void;
  renderChapter?: (ctx: {
    chapter: NarrativeChapter;
    state: BeatState;
  }) => ReactNode;
  /** Registers the quest-name input node for focus + the chapter rail node for scroll. */
  registerNameInput(node: HTMLInputElement | null): void;
  registerRail(node: HTMLElement | null): void;
}

// Tier-C primitive prop types.

export interface QuestTitleProps {
  title: string;
  isDefault?: boolean;
  className?: string;
}

export interface QuestNameFieldProps {
  value: string;
  onChange: (value: string) => void;
  onSave: () => void;
  onCancel: () => void;
  inputRef?: (node: HTMLInputElement | null) => void;
  className?: string;
}

export interface ChapterBeatProps {
  chapter: NarrativeChapter;
  state: BeatState;
  milestone?: Milestone;
  onClick?: (chapter: NarrativeChapter) => void;
  className?: string;
}

export interface ChapterRailProps {
  beats: DerivedBeat[];
  onBeatClick?: (chapter: NarrativeChapter) => void;
  renderChapter?: (ctx: {
    chapter: NarrativeChapter;
    state: BeatState;
  }) => ReactNode;
  className?: string;
}

import type { Team } from "../types";

/**
 * Resolve the displayed quest title (the never-forced core, system §5.2 / D-A1).
 * A blank or whitespace-only `questName` is treated as "no quest name" → falls
 * back to the literal team name. Pure, framework-free, SSR-safe, test-ready.
 */
export function resolveQuestTitle(team: Pick<Team, "name" | "questName">): {
  title: string;
  isDefault: boolean;
} {
  const custom = team.questName?.trim();
  return custom
    ? { title: custom, isDefault: false }
    : { title: team.name, isDefault: true };
}

import type { DerivedBeat, Milestone, NarrativeChapter } from "../types";

/**
 * Derive each chapter's beat state from its milestone (LOCK — D-A2). Pure,
 * framework-free, SSR-safe, test-ready, order-independent (stable sort on
 * `NarrativeChapter.order`, `Milestone.order` tie-break):
 *
 *   done     = milestone.done === true
 *   current  = the FIRST not-done beat by order ("you are here")
 *   upcoming = the rest
 *
 * An unresolved `milestoneId` (no matching milestone) is treated as not-done
 * (so it can become current/upcoming) and flagged `unresolved` — the part warns
 * (dev-only) + renders it gracefully; **never throws**.
 */
export function deriveBeats(
  chapters: NarrativeChapter[],
  milestones: Milestone[],
): DerivedBeat[] {
  const byId = new Map(milestones.map((m) => [m.id, m]));

  const ordered = [...chapters].sort(
    (a, b) =>
      a.order - b.order ||
      (byId.get(a.milestoneId)?.order ?? 0) -
        (byId.get(b.milestoneId)?.order ?? 0),
  );

  let currentAssigned = false;
  return ordered.map((chapter) => {
    const milestone = byId.get(chapter.milestoneId);
    const unresolved = milestone === undefined;
    const done = milestone?.done === true;

    let state: DerivedBeat["state"];
    if (done) {
      state = "done";
    } else if (!currentAssigned) {
      state = "current";
      currentAssigned = true;
    } else {
      state = "upcoming";
    }

    return { chapter, milestone, state, unresolved };
  });
}

"use client";

import * as React from "react";

import type { TeamQuestLogContextValue } from "../types";

export const TeamQuestLogContext =
  React.createContext<TeamQuestLogContextValue | null>(null);

/**
 * Read the quest-log state from a surrounding `TeamQuestLogRoot`.
 * For hand-assembled layouts; throws if used outside a `Root`.
 */
export function useTeamQuestLog(): TeamQuestLogContextValue {
  const ctx = React.useContext(TeamQuestLogContext);
  if (ctx === null) {
    throw new Error("useTeamQuestLog must be used within a <TeamQuestLogRoot>.");
  }
  return ctx;
}

"use client";

import * as React from "react";

import type { GamificationEvent } from "../types";

/**
 * Visibility-based `narrative.chapter-viewed` telemetry (LOCK — D-A3). ONE
 * IntersectionObserver over all beat nodes (not one per beat), threshold 0.5;
 * **fire-once per `chapterId` per mount** via a ref Set (re-render / re-entry /
 * scroll-back never re-emit). SSR/jsdom-safe (observer built in an effect,
 * guarded on `typeof IntersectionObserver`). No `onEvent` → no observer.
 *
 * Returns a `containerRef` to place on the rail wrapper (beat nodes are found by
 * `[data-chapter-id]` within it) + a `fireForChapter(id)` fallback the click
 * path calls when IO is unavailable (still fire-once via the same Set).
 */
export function useChapterViewTelemetry(args: {
  teamId: string;
  /** A stable key of the current chapter ids — re-observes when the beat set changes. */
  chapterKey: string;
  onEvent?: (event: GamificationEvent) => void;
}): {
  containerRef: React.RefObject<HTMLDivElement | null>;
  fireForChapter: (chapterId: string) => void;
} {
  const { teamId, chapterKey, onEvent } = args;

  const containerRef = React.useRef<HTMLDivElement | null>(null);
  const firedRef = React.useRef<Set<string>>(new Set());
  const onEventRef = React.useRef(onEvent);
  React.useEffect(() => {
    onEventRef.current = onEvent;
  });

  const emit = React.useCallback(
    (chapterId: string) => {
      if (firedRef.current.has(chapterId)) return;
      firedRef.current.add(chapterId);
      onEventRef.current?.({
        type: "narrative.chapter-viewed",
        teamId,
        chapterId,
      });
    },
    [teamId],
  );

  const hasHandler = Boolean(onEvent);

  React.useEffect(() => {
    if (!hasHandler) return;
    const container = containerRef.current;
    if (!container) return;
    // IO unavailable (SSR snapshot / jsdom / ancient) → the click fallback covers it.
    if (typeof IntersectionObserver === "undefined") return;

    const observer = new IntersectionObserver(
      (entries) => {
        for (const entry of entries) {
          if (!entry.isIntersecting) continue;
          const id = (entry.target as HTMLElement).dataset.chapterId;
          if (id) emit(id);
        }
      },
      { threshold: 0.5 },
    );

    const nodes = container.querySelectorAll<HTMLElement>("[data-chapter-id]");
    nodes.forEach((n) => observer.observe(n));
    return () => observer.disconnect();
    // `chapterKey` re-runs the effect when beats are added/removed.
  }, [hasHandler, emit, chapterKey]);

  return { containerRef, fireForChapter: emit };
}

"use client";

import * as React from "react";

import { cn } from "@/lib/utils";

import { TeamQuestLogContext } from "../hooks/use-team-quest-log";
import { deriveBeats } from "../lib/derive-beats";
import { resolveQuestTitle } from "../lib/resolve-title";
import type {
  TeamQuestLogContextValue,
  TeamQuestLogHandle,
  TeamQuestLogRootProps,
} from "../types";

/**
 * Tier B — headless provider. The single source of state: the resolved quest
 * title (`questName?.trim() || name` — the never-forced core), the transient
 * name draft/edit state (UI state, not data state — controlled, D-06), the
 * memoized beat derivation, chapter interaction + telemetry pass-through, and
 * the imperative handle. Renders `children`, no layout opinion beyond a labelled
 * region + `reveal-up`.
 */
export const TeamQuestLogRoot = React.forwardRef<
  TeamQuestLogHandle,
  TeamQuestLogRootProps
>(function TeamQuestLogRoot(
  {
    team,
    milestones,
    chapters,
    editableName = true,
    onQuestNameChange,
    onEvent,
    onChapterClick,
    renderChapter,
    children,
    className,
    "aria-label": ariaLabel,
  },
  ref,
) {
  const { title, isDefault } = React.useMemo(
    () => resolveQuestTitle(team),
    [team],
  );

  const beats = React.useMemo(
    () => deriveBeats(chapters, milestones),
    [chapters, milestones],
  );

  const canEditName = editableName && typeof onQuestNameChange === "function";

  // Transient draft/edit state (UI, not data — D-06 intact).
  const [editing, setEditing] = React.useState(false);
  const [draft, setDraft] = React.useState("");

  const startEditing = React.useCallback(() => {
    if (!canEditName) return;
    setDraft(isDefault ? "" : title);
    setEditing(true);
  }, [canEditName, isDefault, title]);

  const onQuestNameChangeRef = React.useRef(onQuestNameChange);
  React.useEffect(() => {
    onQuestNameChangeRef.current = onQuestNameChange;
  });

  const saveDraft = React.useCallback(() => {
    // Blank/whitespace ⇒ "" ⇒ host clears questName ⇒ title reverts (the skip path).
    onQuestNameChangeRef.current?.(draft.trim());
    setEditing(false);
  }, [draft]);

  const cancelEditing = React.useCallback(() => setEditing(false), []);

  // Node registries for the imperative handle.
  const nameInputRef = React.useRef<HTMLInputElement | null>(null);
  const railRef = React.useRef<HTMLElement | null>(null);
  const registerNameInput = React.useCallback(
    (node: HTMLInputElement | null) => {
      nameInputRef.current = node;
    },
    [],
  );
  const registerRail = React.useCallback((node: HTMLElement | null) => {
    railRef.current = node;
  }, []);

  React.useImperativeHandle(
    ref,
    () => ({
      focusNameEditor() {
        startEditing(); // QuestNameField auto-focuses its input on mount.
      },
      scrollToChapter(chapterId: string) {
        const node = railRef.current?.querySelector<HTMLElement>(
          `[data-chapter-id="${chapterId}"]`,
        );
        node?.scrollIntoView({ block: "nearest" });
      },
    }),
    [startEditing],
  );

  const contextValue = React.useMemo<TeamQuestLogContextValue>(
    () => ({
      team,
      title,
      isDefaultTitle: isDefault,
      beats,
      editableName,
      canEditName,
      editing,
      draft,
      startEditing,
      setDraft,
      saveDraft,
      cancelEditing,
      onChapterClick,
      onEvent,
      renderChapter,
      registerNameInput,
      registerRail,
    }),
    [
      team,
      title,
      isDefault,
      beats,
      editableName,
      canEditName,
      editing,
      draft,
      startEditing,
      saveDraft,
      cancelEditing,
      onChapterClick,
      onEvent,
      renderChapter,
      registerNameInput,
      registerRail,
    ],
  );

  return (
    <TeamQuestLogContext.Provider value={contextValue}>
      <section
        aria-label={ariaLabel ?? `${title} — team quest log`}
        className={cn("reveal-up flex w-full flex-col gap-5", className)}
      >
        {children}
      </section>
    </TeamQuestLogContext.Provider>
  );
});

"use client";

import * as React from "react";
import { Check, Pencil, Sparkles, X } from "lucide-react";

import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { cn } from "@/lib/utils";

import { useTeamQuestLog } from "../hooks/use-team-quest-log";
import type { QuestNameFieldProps, QuestTitleProps } from "../types";

/**
 * Tier C — dumb resolved-title display. `isDefault` (falling back to the literal
 * team name) is a subtle affordance hook, never a nag.
 */
export function QuestTitle({ title, isDefault = false, className }: QuestTitleProps) {
  return (
    <h2
      className={cn(
        "truncate text-lg font-semibold",
        isDefault ? "text-foreground" : "text-foreground",
        className,
      )}
      title={title}
    >
      {title}
    </h2>
  );
}

/**
 * Tier C — dumb controlled name input + save/cancel. `Enter` saves, `Escape`
 * cancels; a blank save is allowed (the revert/skip path). Auto-focuses on mount
 * (edit mode entered). Plain controlled `<input>` — no backend-specific props,
 * so it stays portable across the Radix↔Base-UI `input` (a simple wrapper).
 */
export function QuestNameField({
  value,
  onChange,
  onSave,
  onCancel,
  inputRef,
  className,
}: QuestNameFieldProps) {
  const localRef = React.useRef<HTMLInputElement | null>(null);
  const setRef = React.useCallback(
    (node: HTMLInputElement | null) => {
      localRef.current = node;
      inputRef?.(node);
    },
    [inputRef],
  );

  React.useEffect(() => {
    localRef.current?.focus();
    localRef.current?.select();
  }, []);

  return (
    <div className={cn("flex items-center gap-1.5", className)}>
      <Input
        ref={setRef}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onKeyDown={(e) => {
          if (e.key === "Enter") {
            e.preventDefault();
            onSave();
          } else if (e.key === "Escape") {
            e.preventDefault();
            onCancel();
          }
        }}
        aria-label="Quest name"
        placeholder="Name your quest…"
        className="max-w-xs"
      />
      <Button type="button" size="icon" className="size-8" aria-label="Save quest name" onClick={onSave}>
        <Check aria-hidden />
      </Button>
      <Button
        type="button"
        size="icon"
        variant="ghost"
        className="size-8"
        aria-label="Cancel"
        onClick={onCancel}
      >
        <X aria-hidden />
      </Button>
    </div>
  );
}

/**
 * Tier B — the quest-name surface. Display the resolved title + a quiet edit
 * affordance (a "Name your quest" invitation when on the default, an edit pencil
 * when custom). Never a blocking prompt. The edit affordance is gated on
 * `canEditName` (editable + a save handler wired). In edit mode → `QuestNameField`.
 */
export function TeamQuestNameEditor({ className }: { className?: string }) {
  const {
    title,
    isDefaultTitle,
    canEditName,
    editing,
    draft,
    startEditing,
    setDraft,
    saveDraft,
    cancelEditing,
    registerNameInput,
  } = useTeamQuestLog();

  if (editing) {
    return (
      <QuestNameField
        value={draft}
        onChange={setDraft}
        onSave={saveDraft}
        onCancel={cancelEditing}
        inputRef={registerNameInput}
        className={className}
      />
    );
  }

  return (
    <div className={cn("flex items-center gap-2", className)}>
      <QuestTitle title={title} isDefault={isDefaultTitle} />
      {canEditName ? (
        isDefaultTitle ? (
          <Button
            type="button"
            size="sm"
            variant="ghost"
            className="gap-1 text-muted-foreground"
            onClick={startEditing}
          >
            <Sparkles aria-hidden className="size-3.5" /> Name your quest
          </Button>
        ) : (
          <Button
            type="button"
            size="icon"
            variant="ghost"
            className="size-7 text-muted-foreground"
            aria-label="Edit quest name"
            onClick={startEditing}
          >
            <Pencil aria-hidden className="size-3.5" />
          </Button>
        )
      ) : null}
    </div>
  );
}

"use client";

import * as React from "react";
import { BookOpen } from "lucide-react";

import { cn } from "@/lib/utils";

import { useChapterViewTelemetry } from "../hooks/use-chapter-view-telemetry";
import { useTeamQuestLog } from "../hooks/use-team-quest-log";
import { ChapterBeat } from "./chapter-beat";
import type { ChapterRailProps } from "../types";

/**
 * Tier C — quiet empty-state placeholder (no chapters authored). Never an error.
 */
export function EmptyNarrative({ className }: { className?: string }) {
  return (
    <div
      className={cn(
        "flex flex-col items-center gap-2 rounded-lg border border-dashed border-border bg-muted/30 px-4 py-8 text-center",
        className,
      )}
    >
      <BookOpen aria-hidden className="size-5 text-muted-foreground" />
      <p className="text-sm text-muted-foreground">
        Your team&apos;s story will appear here as milestones are reached.
      </p>
    </div>
  );
}

/**
 * Tier C — the vertical rail: a connecting spine (the done portion accents in
 * signal-lime, the upcoming portion is muted) mapping `beats[]` to `ChapterBeat`s.
 * Prop-driven, context-free.
 */
export function ChapterRail({
  beats,
  onBeatClick,
  renderChapter,
  className,
}: ChapterRailProps) {
  return (
    <div role="list" className={cn("relative flex flex-col", className)}>
      {beats.map((beat, i) => {
        const isLast = i === beats.length - 1;
        return (
          <div key={beat.chapter.id} className="relative">
            {!isLast ? (
              <span
                aria-hidden
                className={cn(
                  "absolute top-7 bottom-0 left-[13px] w-px",
                  beat.state === "done" ? "bg-primary" : "bg-border",
                )}
              />
            ) : null}
            {renderChapter ? (
              <div role="listitem" data-chapter-id={beat.chapter.id}>
                {renderChapter({ chapter: beat.chapter, state: beat.state })}
              </div>
            ) : (
              <ChapterBeat
                chapter={beat.chapter}
                state={beat.state}
                milestone={beat.milestone}
                onClick={onBeatClick}
              />
            )}
          </div>
        );
      })}
    </div>
  );
}

/**
 * Tier B — the chapter timeline surface. Reads the derived beats, attaches the
 * fire-once visibility telemetry (one IntersectionObserver over all beat nodes),
 * and renders the `ChapterRail` (or `EmptyNarrative` when there are no chapters).
 * Beats are interactive only when `onChapterClick` is wired (capability-gating).
 */
export function TeamQuestChapters({ className }: { className?: string }) {
  const { team, beats, onChapterClick, onEvent, renderChapter, registerRail } =
    useTeamQuestLog();

  const chapterKey = beats.map((b) => b.chapter.id).join(",");
  const { containerRef, fireForChapter } = useChapterViewTelemetry({
    teamId: team.id,
    chapterKey,
    onEvent,
  });

  // Dev-only: surface any chapter whose milestoneId matched no milestone (it
  // renders gracefully as upcoming, never crashes — §7). NODE_ENV is the one
  // sanctioned env reference, kept in a function body (erased in prod builds).
  React.useEffect(() => {
    if (process.env.NODE_ENV === "production") return;
    const missing = beats.filter((b) => b.unresolved);
    if (missing.length > 0) {
      console.warn(
        `[team-quest-log-01] ${missing.length} chapter(s) reference an unknown milestoneId: ${missing
          .map((b) => b.chapter.milestoneId)
          .join(", ")}`,
      );
    }
  }, [beats]);

  const setNode = React.useCallback(
    (node: HTMLDivElement | null) => {
      containerRef.current = node;
      registerRail(node);
    },
    [containerRef, registerRail],
  );

  const handleBeatClick = React.useCallback(
    (chapter: (typeof beats)[number]["chapter"]) => {
      onChapterClick?.(chapter);
      // Telemetry fallback when IO is unavailable — fire-once via the shared Set.
      fireForChapter(chapter.id);
    },
    [onChapterClick, fireForChapter],
  );

  return (
    <div ref={setNode} className={cn("w-full", className)}>
      {beats.length === 0 ? (
        <EmptyNarrative />
      ) : (
        <ChapterRail
          beats={beats}
          onBeatClick={onChapterClick ? handleBeatClick : undefined}
          renderChapter={renderChapter}
        />
      )}
    </div>
  );
}

"use client";

import * as React from "react";
import { Check, Circle, MapPin } from "lucide-react";

import { cn } from "@/lib/utils";

import type { ChapterBeatProps } from "../types";

const MONTHS = [
  "Jan", "Feb", "Mar", "Apr", "May", "Jun",
  "Jul", "Aug", "Sep", "Oct", "Nov", "Dec",
];

/**
 * Deterministic, locale/TZ-independent date format (UTC parts + fixed month
 * names) so a `doneAt` reads identically on server + client — no hydration
 * mismatch. Returns null for an unparseable value.
 */
function formatDoneAt(iso: string): string | null {
  const d = new Date(iso);
  if (Number.isNaN(d.getTime())) return null;
  return `${d.getUTCDate()} ${MONTHS[d.getUTCMonth()]} ${d.getUTCFullYear()}`;
}

const STATE_LABEL = {
  done: "completed",
  current: "current",
  upcoming: "upcoming",
} as const;

/**
 * Tier C — a single chapter beat: a state marker (with a **non-color** cue —
 * `Check` done / `MapPin` "you are here" current / hollow `Circle` upcoming, so
 * state reads without color, D-13/§10), the chapter title, the milestone label
 * subtitle, and an optional "completed" date. Interactive only when `onClick` is
 * passed (a real `<button>`); otherwise static. Tagged `data-chapter-id` for the
 * visibility telemetry + scroll-into-view.
 */
export function ChapterBeat({
  chapter,
  state,
  milestone,
  onClick,
  className,
}: ChapterBeatProps) {
  const interactive = typeof onClick === "function";
  const doneAtText =
    state === "done" && milestone?.doneAt ? formatDoneAt(milestone.doneAt) : null;

  const marker = (
    <span
      aria-hidden
      className={cn(
        "relative z-10 flex size-7 shrink-0 items-center justify-center rounded-full border transition-[transform,box-shadow,border-color,background-color,color] duration-200 ease-out motion-safe:group-hover:scale-110",
        state === "done" &&
          "border-primary bg-primary text-primary-foreground group-hover:shadow-md group-hover:shadow-primary/30",
        state === "current" &&
          "border-primary bg-background text-primary ring-2 ring-primary/30 group-hover:ring-primary/50",
        state === "upcoming" &&
          "border-border bg-muted text-muted-foreground group-hover:border-primary/40 group-hover:text-foreground",
      )}
    >
      {state === "done" ? (
        <Check className="size-4" />
      ) : state === "current" ? (
        <MapPin className="size-4" />
      ) : (
        <Circle className="size-3" />
      )}
    </span>
  );

  const body = (
    <span className="flex min-w-0 flex-col gap-0.5 pb-4 text-left">
      <span
        className={cn(
          "truncate text-sm font-medium",
          state === "upcoming" ? "text-muted-foreground" : "text-foreground",
        )}
      >
        {chapter.title}
      </span>
      {milestone?.label ? (
        <span className="truncate text-xs text-muted-foreground">
          {milestone.label}
        </span>
      ) : null}
      {doneAtText ? (
        <span className="font-mono text-[11px] text-muted-foreground">
          Completed {doneAtText}
        </span>
      ) : null}
    </span>
  );

  const accessibleName = `${chapter.title} — ${STATE_LABEL[state]}`;

  const inner = (
    <>
      {marker}
      {body}
    </>
  );

  if (interactive) {
    return (
      <button
        type="button"
        role="listitem"
        data-chapter-id={chapter.id}
        aria-label={accessibleName}
        onClick={() => onClick?.(chapter)}
        className={cn(
          "group flex w-full items-start gap-3 rounded-md text-left outline-none",
          "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1 focus-visible:ring-offset-background",
          className,
        )}
      >
        {inner}
      </button>
    );
  }

  return (
    <div
      role="listitem"
      data-chapter-id={chapter.id}
      aria-label={accessibleName}
      className={cn("group flex items-start gap-3", className)}
    >
      {inner}
    </div>
  );
}
